mapper.select:
/*selectUser*/ SELECT * FROM ( SELECT U.USER_NAME, U.ROOM_NAME, U.LV, U.EXP_CUR, U.EXP_NEXT, U.HP_CUR, U.HP_MAX, U.HP_REGEN, U.ATK_MIN, U.ATK_MAX, U.CRIT_RATE, U.CRIT_DMG, U.TARGET_MON, U.INSERT_DATE, U.JOB, U.JOB_CHANGE_DATE, U.BLESS_YN, U.PROC_DATE, NVL(U.NIGHTMARE_YN, 0) AS NIGHTMARE_YN,
NVL(SP_SUM.TOTAL_SP,0) AS TOTAL_SP
FROM TBOT_POINT_NEW_USER U
LEFT JOIN ( SELECT USER_NAME, SUM(SP_VAL) AS TOTAL_SP FROM ( /* INVENTORY SP */ SELECT A.USER_NAME, ( CASE WHEN A.GAIN_TYPE='BUY_MERCHANT' THEN ROUND(B.ITEM_SELL_PRICE*0.9) ELSE B.ITEM_SELL_PRICE END ) * POWER( 10000, CASE WHEN B.ITEM_SELL_PRICE_EXT IS NULL OR B.ITEM_SELL_PRICE_EXT='' THEN 0 ELSE ASCII(B.ITEM_SELL_PRICE_EXT)-ASCII('a')+1 END ) * A.QTY AS SP_VAL
FROM TBOT_POINT_NEW_INVENTORY A JOIN TBOT_POINT_NEW_ITEM B ON A.ITEM_ID=B.ITEM_ID
WHERE A.GAIN_TYPE NOT IN ('DROP','DROP3','DROP5','DROP9','STEAL') AND A.DEL_YN='0'
UNION ALL
/* POINT LOG SP */ SELECT R.USER_NAME, R.SCORE * POWER( 10000, CASE WHEN R.SCORE_EXT IS NULL OR R.SCORE_EXT='' THEN 0 ELSE ASCII(R.SCORE_EXT)-ASCII('a')+1 END )
FROM TBOT_POINT_RANK R WHERE R.NEW_YN='1'
) GROUP BY USER_NAME ) SP_SUM ON SP_SUM.USER_NAME=U.USER_NAME
WHERE U.USER_NAME=#{userName}
ORDER BY U.PROC_DATE DESC NULLS LAST, U.INSERT_DATE DESC NULLS LAST, U.LV DESC, U.EXP_CUR DESC ) WHERE ROWNUM=1

/*selectMonsterByNo*/
