/*selectLastAttackTime*/
  SELECT MAX(INSERT_DATE)
  FROM TBOT_POINT_NEW_BATTLE_LOG
  WHERE USER_NAME = #{userName}
    AND GAIN_EXP >= 0

mapper.insert:
/*insertBattleLog*/
  INSERT INTO TBOT_POINT_NEW_BATTLE_LOG
    (USER_NAME, ROOM_NAME, LV, TARGET_MON_LV,
     GAIN_EXP, ATK_DMG, MON_DMG, ATK_CRIT_YN,
     MON_PATTEN, INSERT_DATE, KILL_YN, NOW_YN, DROP_YN, DEATH_YN, LUCKY_YN, BUFF_YN
     ,JOB_SKILL_YN,JOB,NIGHTMARE_YN
     ,SPECIAL_BUFF_START,SPECIAL_BUFF_ING,SPECIAL_BUFF_CODE
     )
  VALUES
    (#{userName}, #{roomName}, #{lv}, #{targetMonLv},
     #{gainExp}, #{atkDmg}, #{monDmg}, #{atkCritYn},
     #{monPatten}, SYSDATE, #{killYn}, #{nowYn}, #{dropYn}, #{deathYn}, #{luckyYn},#{buffYn}
     ,#{jobSkillYn},#{job},#{nightmareYn}
     ,#{specialBuffStart},#{specialBuffIng},#{specialBuffCode,jdbcType=VARCHAR}
     )

/*insertBattleLogBatch*/ INSERT ALL
INTO TBOT_POINT_NEW_BATTLE_LOG (USER_NAME, ROOM_NAME, LV, TARGET_MON_LV, GAIN_EXP, ATK_DMG, MON_DMG, ATK_CRIT_YN, MON_PATTEN, INSERT_DATE, KILL_YN, NOW_YN, DROP_YN, DEATH_YN, LUCKY_YN, BUFF_YN, JOB_SKILL_YN, JOB, NIGHTMARE_YN, SPECIAL_BUFF_START, SPECIAL_BUFF_ING, SPECIAL_BUFF_CODE) VALUES (#{log.userName}, #{log.roomName}, #{log.lv}, #{log.targetMonLv}, #{log.gainExp}, #{log.atkDmg}, #{log.monDmg}, #{log.atkCritYn}, #{log.monPatten}, SYSTIMESTAMP - NUMTODSINTERVAL(#{log.shotIndex}+2, 'SECOND'), #{log.killYn}, #{log.nowYn}, #{log.dropYn}, #{log.deathYn}, #{log.luckyYn}, #{log.buffYn}, #{log.jobSkillYn}, #{log.job}, #{log.nightmareYn}, 0, 0, null)
SELECT 1 FROM DUAL

