mapper.select:
/*selectParam1ToNewUserSearch*/ SELECT A.USER_NAME FROM TBOT_POINT_NEW_USER A WHERE UPPER(A.USER_NAME) LIKE UPPER(#{param1,jdbcType=VARCHAR}) || '%'
AND NOT EXISTS ( SELECT 1 FROM TBOT_BLOCK C WHERE UPPER(C.USER_NAME) = UPPER(#{param1,jdbcType=VARCHAR})
) GROUP BY A.USER_NAME, A.ROOM_NAME HAVING 1 = CASE WHEN MAX(A.PROC_DATE) >= TRUNC(SYSDATE) - 3 THEN 1 ELSE 0 END ORDER BY CASE WHEN LENGTH(#{param1,jdbcType=VARCHAR}) = LENGTH(A.USER_NAME) THEN 1 ELSE 0 END DESC

/* selectInventorySummaryAll */ SELECT i.item_id AS ITEM_ID,
/* 🔹 기존 이름 가공 로직 유지 */ CASE WHEN NVL(inv.gain_type,'DROP') = 'DROP3' THEN '빛' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'DROP5' THEN '어둠' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'DROP9' THEN '음양' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'STEAL' THEN NVL(i.item_name, '알 수 없음') || '조각' ELSE NVL(i.item_name, '알 수 없음') END AS ITEM_NAME,
SUM(inv.qty) AS TOTAL_QTY,
/* 🔹 기존 컬럼 */ NVL(MAX(i.item_sell_price), 0) AS ITEM_SELL_PRICE, NVL(MAX(i.item_sell_price_EXT), '') AS ITEM_SELL_PRICE_EXT, NVL(MAX(i.item_type), '') AS ITEM_TYPE,
/* 🔥 아이템 상세 옵션 (추가) */ NVL(MAX(i.ATK_MIN), 0) AS ATK_MIN, NVL(MAX(i.ATK_MAX), 0) AS ATK_MAX, NVL(MAX(i.ATK_CRI), 0) AS ATK_CRI, NVL(MAX(i.HP_REGEN), 0) AS HP_REGEN, NVL(MAX(i.HP_MAX), 0) AS HP_MAX, NVL(MAX(i.CRI_DMG), 0) AS CRI_DMG, NVL(MAX(i.HP_MAX_RATE), 0) AS HP_MAX_RATE, NVL(MAX(i.ATK_MAX_RATE), 0) AS ATK_MAX_RATE
FROM TBOT_POINT_NEW_INVENTORY inv LEFT JOIN TBOT_POINT_NEW_ITEM i ON i.item_id = inv.item_id
WHERE inv.user_name = #{userName} AND inv.del_yn = '0' AND inv.item_id > 90 GROUP BY i.item_id, -1, CASE WHEN NVL(inv.gain_type,'DROP') = 'DROP3' THEN '빛' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'DROP5' THEN '어둠' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'DROP9' THEN '음양' || NVL(i.item_name, '알 수 없음') WHEN NVL(inv.gain_type,'DROP') = 'STEAL' THEN NVL(i.item_name, '알 수 없음') || '조각' ELSE NVL(i.item_name, '알 수 없음') END
ORDER BY i.item_id

