      /* selectRandomBlessTargets */
      SELECT USER_NAME
	    FROM (
	        SELECT A.USER_NAME
	        FROM TBOT_POINT_NEW_USER A
	        WHERE A.PROC_DATE > SYSDATE - 1
	          AND A.USER_NAME != #{attacker}
	          AND NVL(A.BLESS_YN,0) = 0
